<?php
function generateReport(PDO $pdo) {
    // Base query and parameters array
    $query = "SELECT * FROM reports WHERE 1=1";
    $params = [];

    // Check for status filter
    if (!empty($_POST['status'])) {
        $query .= " AND status = :status";
        $params[':status'] = $_POST['status'];
    }
    
    // Check for category filter
    if (!empty($_POST['category'])) {
        $query .= " AND category = :category";
        $params[':category'] = $_POST['category'];
    }
    
    // Check for start date filter
    if (!empty($_POST['start_date'])) {
        $query .= " AND report_date >= :start_date";
        $params[':start_date'] = $_POST['start_date'];
    }
    
    // Check for end date filter
    if (!empty($_POST['end_date'])) {
        $query .= " AND report_date <= :end_date";
        $params[':end_date'] = $_POST['end_date'];
    }
    
    // Optionally add an ORDER BY clause
    $query .= " ORDER BY report_date DESC";

    try {
        $stmt = $pdo->prepare($query);
        $stmt->execute($params);
        $reports = $stmt->fetchAll(PDO::FETCH_ASSOC);
        return $reports;
    } catch (PDOException $e) {
        // log error or handle as needed
        error_log("Error generating report: " . $e->getMessage());
        return false;
    }
}

